export interface CipherSuiteRecord {
  /** Code point as 0xNNNN (upper-case, 4 hex digits). */
  hex: string;
  /** Numeric code point (0x0000-0xFFFF) for lookup. */
  code: number;
  /** Authoritative IANA name (e.g. TLS_AES_128_GCM_SHA256). */
  name: string;
  /** IANA DTLS-OK flag. */
  dtls: boolean;
  /** IANA "Recommended" column: Y (yes), N (not recommended), D (discouraged). */
  rec: "Y" | "N" | "D";
  /** Reference(s) from the registry, cleaned (e.g. "RFC 8446"). */
  refs: string[];
  /** OpenSSL name, when known (empty if none / TLS 1.3 uses the IANA name). */
  openssl: string;
  /** GnuTLS name, when known. */
  gnutls: string;
}

